CallbackReturn on_configure(const State &) override {
    // 1. Load parameters
    max_speed_ = get_parameter("max_speed").as_double();

    // 2. Validate
    if (max_speed_ <= 0) {
        return CallbackReturn::FAILURE;  // Stay unconfigured
    }

    // 3. Create interfaces (but don't start)
    pub_ = create_lifecycle_publisher<>("topic", 10);
    timer_ = create_timer(100ms, callback);
    timer_->cancel();  // Don't fire yet!

    // 4. Allocate resources
    buffer_ = std::make_shared<Buffer>(1000);

    return CallbackReturn::SUCCESS;  // → Inactive state
}

CallbackReturn on_activate(const State &) override {
    // 1. Activate publishers
    pub_->on_activate();  // Now can publish

    // 2. Start timers
    timer_->reset();  // Start firing

    // 3. Start background tasks
    processing_thread_ = std::thread(&Node::process_loop, this);

    return CallbackReturn::SUCCESS;  // → Active state
}

// Single-phase initialization
Constructor() {
    // Load config AND start immediately
    // No chance to validate or reconfigure before starting!
}

interview_qa.answer:
**CallbackReturn Types:**

```cpp
enum class CallbackReturn {
    SUCCESS = 0,  // Transition successful
    FAILURE = 1,  // Transition failed (recoverable)
    ERROR = 2     // Unrecoverable error
};
```

code_examples:
enum class CallbackReturn {
    SUCCESS = 0,  // Transition successful
    FAILURE = 1,  // Transition failed (recoverable)
    ERROR = 2     // Unrecoverable error
};

CallbackReturn on_configure(const State &) override {
    // Try to load parameter
    declare_parameter("max_speed", 1.0);
    double max_speed = get_parameter("max_speed").as_double();

    if (max_speed <= 0 || max_speed > 10.0) {
        RCLCPP_ERROR(get_logger(),
            "Invalid max_speed: %.2f (must be 0-10)", max_speed);

        // Node is fine, just bad config
        return CallbackReturn::FAILURE;
    }

    max_speed_ = max_speed;
    return CallbackReturn::SUCCESS;
}

CallbackReturn on_configure(const State &) override {
    try {
        // Critical operation
        hardware_driver_ = std::make_shared<HardwareDriver>();
        hardware_driver_->initialize();

        // Validate driver
        if (!hardware_driver_->is_valid()) {
            throw std::runtime_error("Hardware driver corrupted!");
        }

        return CallbackReturn::SUCCESS;

    } catch (std::exception& e) {
        RCLCPP_FATAL(get_logger(),
            "Fatal error in configure: %s", e.what());

        // Unrecoverable error - node may be in bad state
        return CallbackReturn::ERROR;
    }
}

CallbackReturn on_error(const State &) override {
    RCLCPP_ERROR(get_logger(), "In error state, cleaning up...");

    // Emergency cleanup
    if (hardware_driver_) {
        hardware_driver_->shutdown();
        hardware_driver_.reset();
    }

    // Release any partially-allocated resources
    timer_.reset();
    publisher_.reset();

    return CallbackReturn::SUCCESS;
}

CallbackReturn on_configure(const State &) override {
    try {
        // Validate parameters
        int fps = get_parameter("fps").as_int();
        if (fps <= 0) {
            // Recoverable - just bad config
            return CallbackReturn::FAILURE;
        }

        // Allocate resources
        camera_ = std::make_shared<Camera>();
        camera_->open();

        // Check if camera valid
        if (!camera_->is_open()) {
            // Recoverable - camera not connected
            camera_.reset();
            return CallbackReturn::FAILURE;
        }

        return CallbackReturn::SUCCESS;

    } catch (std::exception& e) {
        // Unrecoverable exception
        RCLCPP_FATAL(get_logger(), "Exception: %s", e.what());

        // Clean up partial allocations
        camera_.reset();

        return CallbackReturn::ERROR;
    }
}

interview_qa.answer:
**Regular Publisher:**

```cpp
// In regular node
auto pub = create_publisher<String>("topic", 10);

// Publishes immediately
pub->publish(msg);  // ✅ Published!
```

code_examples:
// In regular node
auto pub = create_publisher<String>("topic", 10);

// Publishes immediately
pub->publish(msg);  // ✅ Published!

// In lifecycle node
auto pub = create_lifecycle_publisher<String>("topic", 10);

// In Inactive state:
pub->publish(msg);  // ❌ NOT published! (silently dropped)

// Must activate first:
pub->on_activate();

// Now in Active state:
pub->publish(msg);  // ✅ Published!

class LifecyclePublisherNode : public LifecycleNode {
    rclcpp_lifecycle::LifecyclePublisher<String>::SharedPtr pub_;
    rclcpp::TimerBase::SharedPtr timer_;

    CallbackReturn on_configure(const State &) override {
        // Create publisher (inactive by default)
        pub_ = create_lifecycle_publisher<String>("topic", 10);

        // Create timer
        timer_ = create_timer(1s, [this]() { timer_callback(); });
        timer_->cancel();  // Don't start yet

        return CallbackReturn::SUCCESS;
    }

    CallbackReturn on_activate(const State &) override {
        // Activate publisher
        pub_->on_activate();

        // Start timer
        timer_->reset();

        RCLCPP_INFO(get_logger(), "Now publishing!");
        return CallbackReturn::SUCCESS;
    }

    CallbackReturn on_deactivate(const State &) override {
        // Deactivate publisher
        pub_->on_deactivate();

        // Stop timer
        timer_->cancel();

        RCLCPP_INFO(get_logger(), "Stopped publishing");
        return CallbackReturn::SUCCESS;
    }

    void timer_callback() {
        auto msg = String();
        msg.data = "Hello";

        // Only publishes if node is Active
        pub_->publish(msg);
    }
};

// Regular subscription in lifecycle node
auto sub = create_subscription<String>(
    "topic", 10,
    std::bind(&Node::callback, this, _1)
);

// Receives messages even when node is Inactive!

class LifecycleSubNode : public LifecycleNode {
    bool is_active_ = false;

    CallbackReturn on_activate(const State &) override {
        is_active_ = true;
        return CallbackReturn::SUCCESS;
    }

    CallbackReturn on_deactivate(const State &) override {
        is_active_ = false;
        return CallbackReturn::SUCCESS;
    }

    void callback(const String::SharedPtr msg) {
        if (!is_active_) {
            // Ignore messages when not active
            return;
        }

        // Process message
        RCLCPP_INFO(get_logger(), "Received: %s", msg->data.c_str());
    }
};

edge_cases.explanation:
**Scenario:**

Message contains invalid UTF-8 in string field, serialization fails:

```python
msg = my_interfaces.msg.RobotStatus()
msg.robot_id = b'\xff\xfe\xfd'.decode('utf-8', errors='ignore')  # Invalid UTF-8
pub.publish(msg)  # Fails to serialize!
```

**Why:**

ROS2 messages use **UTF-8 strings**. Invalid UTF-8 causes serialization error.

**Solution 1: Validate Strings**

```cpp
#include <string>
#include <stdexcept>

void validate_utf8(const std::string& str) {
    // Basic UTF-8 validation
    for (size_t i = 0; i < str.size(); ) {
        unsigned char c = str[i];

        if (c <= 0x7F) {
            i += 1;
        } else if (c <= 0xDF) {
            if (i + 1 >= str.size()) throw std::invalid_argument("Invalid UTF-8");
            i += 2;
        } else if (c <= 0xEF) {
            if (i + 2 >= str.size()) throw std::invalid_argument("Invalid UTF-8");
            i += 3;
        } else if (c <= 0xF7) {
            if (i + 3 >= str.size()) throw std::invalid_argument("Invalid UTF-8");
            i += 4;
        } else {
            throw std::invalid_argument("Invalid UTF-8");
        }
    }
}

// Before publishing
validate_utf8(msg.robot_id);
publisher_->publish(msg);
```

**Solution 2: Use byte array for binary data**

```msg
# Instead of:
string binary_data    # ❌ Expects UTF-8

# Use:
uint8[] binary_data   # ✅ Raw bytes
```

**Interview Insight:**
String fields must contain valid UTF-8. For binary data, use `uint8[]` instead of `string`. Validate strings before publishing if source is untrusted.

---

**Scenario:**

Message has default values in definition, but code doesn't see them:

```msg
# RobotConfig.msg
float32 max_speed 10.0    # Default value
bool enabled true
```

```cpp
auto msg = my_interfaces::msg::RobotConfig();
std::cout << msg.max_speed;    // Prints 0, not 10!
std::cout << msg.enabled;      // Prints false, not true!
```

**Why:**

**Default values in .msg files are NOT used for initialization!**

They are only documentation/metadata for tools (e.g., GUI parameter editors).

**C++ zero-initializes all fields** by default.

**Solution: Set defaults in code**

```cpp
auto msg = my_interfaces::msg::RobotConfig();
msg.max_speed = 10.0;    // Must set explicitly
msg.enabled = true;
```

Or use constructor (if you modify generated code - not recommended):

```cpp
// Custom wrapper
struct RobotConfigWithDefaults {
    my_interfaces::msg::RobotConfig msg;

    RobotConfigWithDefaults() {
        msg.max_speed = 10.0;
        msg.enabled = true;
    }
};
```

**Interview Insight:**
Default values in .msg files are **documentation only**, not used for initialization. C++ zero-initializes all fields. Always set defaults explicitly in code.

---

code_examples.code:
#include "rclcpp/rclcpp.hpp"
#include "my_robot_interfaces/msg/battery_sensor.hpp"
#include <random>

class BatteryMonitor : public rclcpp::Node
{
public:
    BatteryMonitor() : Node("battery_monitor")
    {
        // Declare parameters
        declare_parameter("publish_rate", 10.0);
        declare_parameter("battery_id", "BAT001");

        auto rate = get_parameter("publish_rate").as_double();
        battery_id_ = get_parameter("battery_id").as_string();

        // Create publisher
        publisher_ = create_publisher<my_robot_interfaces::msg::BatterySensor>(
            "battery_status", 10);

        // Create timer
        timer_ = create_wall_timer(
            std::chrono::milliseconds(static_cast<int>(1000.0 / rate)),
            std::bind(&BatteryMonitor::publish_battery, this));

        // Initialize state
        voltage_ = 24.0;
        current_ = 0.0;
        percentage_ = 100.0;
        state_ = my_robot_interfaces::msg::BatterySensor::FULL;

        RCLCPP_INFO(get_logger(), "Battery monitor started: %s", battery_id_.c_str());
    }

private:
    void publish_battery()
    {
        // Simulate battery discharge
        if (state_ == my_robot_interfaces::msg::BatterySensor::DISCHARGING) {
            percentage_ -= 0.1;
            voltage_ = 20.0 + (percentage_ / 100.0) * 5.0;  // 20-25V range
            current_ = 2.0 + random_float(-0.5, 0.5);

            if (percentage_ <= 0.0) {
                percentage_ = 0.0;
                state_ = my_robot_interfaces::msg::BatterySensor::CRITICAL;
            } else if (percentage_ <= 20.0) {
                state_ = my_robot_interfaces::msg::BatterySensor::CRITICAL;
            }
        }

        // Create message
        auto msg = my_robot_interfaces::msg::BatterySensor();

        msg.header.stamp = now();
        msg.header.frame_id = "battery_link";

        msg.voltage = voltage_;
        msg.current = current_;
        msg.percentage = percentage_;
        msg.temperature = 25.0 + random_float(-2.0, 2.0);
        msg.state = state_;
        msg.is_charging = (state_ == my_robot_interfaces::msg::BatterySensor::CHARGING);
        msg.battery_id = battery_id_;

        publisher_->publish(msg);

        // Log status
        RCLCPP_INFO(get_logger(),
            "Battery: %.1f%% | %.2fV | %.2fA | %s",
            msg.percentage, msg.voltage, msg.current,
            state_to_string(msg.state).c_str());
    }

    std::string state_to_string(uint8_t state)
    {
        switch (state) {
            case my_robot_interfaces::msg::BatterySensor::CHARGING:
                return "CHARGING";
            case my_robot_interfaces::msg::BatterySensor::DISCHARGING:
                return "DISCHARGING";
            case my_robot_interfaces::msg::BatterySensor::FULL:
                return "FULL";
            case my_robot_interfaces::msg::BatterySensor::CRITICAL:
                return "CRITICAL";
            default:
                return "UNKNOWN";
        }
    }

    float random_float(float min, float max)
    {
        static std::random_device rd;
        static std::mt19937 gen(rd());
        std::uniform_real_distribution<float> dist(min, max);
        return dist(gen);
    }

    rclcpp::Publisher<my_robot_interfaces::msg::BatterySensor>::SharedPtr publisher_;
    rclcpp::TimerBase::SharedPtr timer_;

    std::string battery_id_;
    float voltage_;
    float current_;
    float percentage_;
    uint8_t state_;
};

int main(int argc, char** argv)
{
    rclcpp::init(argc, argv);
    rclcpp::spin(std::make_shared<BatteryMonitor>());
    rclcpp::shutdown();
    return 0;
}

edge_cases.explanation:
**Scenario:**

Robot is moving, hardware connection suddenly lost (cable unplugged, network drop):

```
t=0s:   Robot moving, joints at position [1.0, 0.5, 0.3]
t=5s:   Cable unplugged
        read() fails → what values in hw_positions_?
        write() fails → are commands sent?
t=6s:   Robot still moving? Stopped? Unknown state!
```

**Why:**
- USB cable disconnected
- Network timeout
- Hardware fault (motor driver failure)

**Problem:**

```cpp
hardware_interface::return_type read(...) override {
    try {
        read_joint_positions(hw_positions_);
    } catch (SerialException& e) {
        // ❌ Bad: Silently ignore error
        return hardware_interface::return_type::OK;  // Lie!
    }
}

// Controller gets stale data → continues sending commands to disconnected hardware
```

**Solution 1: Return Error on Failure**

```cpp
hardware_interface::return_type read(...) override {
    try {
        read_joint_positions(hw_positions_);
        read_joint_velocities(hw_velocities_);
        return hardware_interface::return_type::OK;

    } catch (SerialException& e) {
        RCLCPP_ERROR(get_logger(), "Hardware read failed: %s", e.what());
        return hardware_interface::return_type::ERROR;  // ✅ Report error
    }
}
```

**Effect:** Controller manager detects error → deactivates controllers → robot stops accepting commands.

**Solution 2: Use Lifecycle States**

```cpp
CallbackReturn on_error(const rclcpp_lifecycle::State &) override {
    RCLCPP_ERROR(get_logger(), "Hardware error! Emergency stop.");

    // Attempt to send stop command
    try {
        emergency_stop();
    } catch (...) {
        // Even emergency stop failed
    }

    // Close connection
    close_serial_port(serial_port_handle_);

    return CallbackReturn::SUCCESS;
}
```

**Solution 3: Watchdog Timer**

```cpp
std::chrono::steady_clock::time_point last_successful_read_;

hardware_interface::return_type read(...) override {
    try {
        read_joint_positions(hw_positions_);
        last_successful_read_ = std::chrono::steady_clock::now();
        return hardware_interface::return_type::OK;

    } catch (SerialException& e) {
        // Check if connection lost for too long
        auto now = std::chrono::steady_clock::now();
        auto duration = std::chrono::duration_cast<std::chrono::seconds>(
            now - last_successful_read_);

        if (duration.count() > 2) {  // > 2 seconds without successful read
            RCLCPP_ERROR(get_logger(), "Hardware connection lost!");
            return hardware_interface::return_type::ERROR;
        }

        return hardware_interface::return_type::OK;  // Tolerate brief failures
    }
}
```

**Interview Insight:**
Hardware connection failures must be detected and handled. Return ERROR from read()/write() to signal failure. Use lifecycle states for error handling. Implement watchdog timers to detect prolonged failures.

