### Control Flow Nodes

```xml
<!-- Sequence: All must succeed -->
<Sequence>
  <Action1/>
  <Action2/>
</Sequence>

<!-- Fallback: One must succeed -->
<Fallback>
  <Option1/>
  <Option2/>
</Fallback>

<!-- Parallel: Concurrent execution -->
<Parallel success_threshold="2">
  <Task1/>
  <Task2/>
</Parallel>
```

### Decorators

```xml
<!-- Retry up to 3 times -->
<Retry num_attempts="3">
  <Action/>
</Retry>

<!-- Timeout after 5 seconds -->
<Timeout seconds="5">
  <Action/>
</Timeout>

<!-- Invert result -->
<Inverter>
  <Condition/>
</Inverter>

<!-- Force success -->
<ForceSuccess>
  <Action/>
</ForceSuccess>
```

